//	# filenames, the first loads iPXE, and the second tells iPXE what to load.
//	# The dhcp-match sets the ipxe tag for requests from iPXE.
//	#dhcp-boot=undionly.kpxe
//	#dhcp-match=set:ipxe,175 # iPXE sends a 175 option.
